import React, { useState } from "react";
import "./Auth.css";
import axios from "axios";

const NewPrediction = () => {
   

  const [form, setForm] = useState({
    Gender: "",
    Education_Level: "",
    Qualification: "",
    Experience: "",
    JobRole: "",
    PrimarySkill: "",
    Location: ""
  });
 

  const [salary, setSalary] = useState("");
  const [stats, setStats] = useState(null);

  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

 const handlePredict = async (e) => {
  e.preventDefault();

  try {
    // API call
    const response = await axios.post(
      "http://localhost:5001/predict",
      form
    );

    const predictedSalary = response.data.salary;
    setSalary(predictedSalary);

 
    let count = localStorage.getItem("predictionCount") || 0;
    count = parseInt(count) + 1;
    localStorage.setItem("predictionCount", count);

  
    localStorage.setItem("lastSalary", predictedSalary);

 
    let roles = JSON.parse(localStorage.getItem("roles")) || [];
    roles.push(form.JobRole);
    localStorage.setItem("roles", JSON.stringify(roles));

  } catch (error) {
    console.error("Prediction error:", error);
    alert("Prediction failed. Check backend.");
  }
};
  const qualificationOptions = {
    Diploma: [
      "Diploma in Computer Engineering",
      "Diploma in Information Technology",
      "Diploma in Software Engineering",
      "Diploma in Web Development"
    ],

    Bachelor: [
      "BCA",
      "B.Tech /B.E",
      "B.Sc",
      "BSc Computer Science",
      "BSc Data Science",
      "BBA",
      "B.Com"
    ],

    Master: [
      "MCA",
      "MSc Computer Science",
      "MSc Data Science",
      "MBA",
      "M.E /M.Tech",
      "M.Com"
    ],

    PhD: [
      "PhD Computer Science",
      "PhD Artificial Intelligence",
      "PhD Machine Learning",
      "PhD Data Science"
    ]
  };

  return (
    <div className="prediction-wrapper">
      <div className="prediction-card">

        <h2>Salary Prediction 💰</h2>

        <form onSubmit={handlePredict} className="prediction-form">

          {/* Gender */}
          <select name="Gender" value={form.Gender} onChange={handleChange} required>
            <option value="">Select Gender</option>
            <option>Male</option>
            <option>Female</option>
            <option>Other</option>
          </select>

          {/* Education Level */}
          <select
            name="Education_Level"
            value={form.Education_Level}
            onChange={handleChange}
            required
          >
            <option value="">Education Level</option>
            <option>Diploma</option>
            <option>Bachelor</option>
            <option>Master</option>
            <option>PhD</option>
          </select>

          {/* Qualification */}
          <select
            name="Qualification"
            value={form.Qualification}
            onChange={handleChange}
            required
          >
            <option value="">Select Qualification</option>

            {form.Education_Level &&
              qualificationOptions[form.Education_Level].map((course, index) => (
                <option key={index}>{course}</option>
              ))}
          </select>

          {/* Experience */}
          <input
            type="number"
            name="Experience"
            placeholder="Total Experience (Years)"
            value={form.Experience}
            onChange={handleChange}
            required
          />

          {/* Job Role */}
          <select name="JobRole" value={form.JobRole} onChange={handleChange} required>

            <option value="">Select Job Role</option>

            <option>Software Engineer</option>
            <option>Frontend Developer</option>
            <option>Backend Developer</option>
            <option>Full Stack Developer</option>
            <option>Data Analyst</option>
            <option>Data Scientist</option>
            <option>Machine Learning Engineer</option>
            <option>AI Engineer</option>
            <option>DevOps Engineer</option>
            <option>Cloud Engineer</option>
            <option>Cybersecurity Analyst</option>
            <option>QA Engineer</option>
            <option>Mobile App Developer</option>
            <option>Blockchain Developer</option>
            <option>Game Developer</option>
            <option>Business Analyst</option>
            <option>Digital Marketing Executive</option>
            <option>Finance Analyst</option>
            <option>Healthcare Analyst</option>
            <option>HR Executive</option>

          </select>

          {/* Primary Skill */}
          <select
            name="PrimarySkill"
            value={form.PrimarySkill}
            onChange={handleChange}
            required
          >

            <option value="">Select Primary Skill</option>

            <option>Java</option>
            <option>C/C++</option>
            <option>Python</option>
            <option>JavaScript</option>
            <option>React</option>
            <option>Node.js</option>
            <option>Angular</option>
            <option>Vue.js</option>
            <option>SQL</option>
            <option>MongoDB</option>
            <option>PostgreSQL</option>
            <option>Machine Learning</option>
            <option>Deep Learning</option>
            <option>TensorFlow</option>
            <option>PyTorch</option>
            <option>Data Analysis</option>
            <option>Power BI</option>
            <option>Tableau</option>
            <option>AWS</option>
            <option>Azure</option>
            <option>Selenium/TestNG</option>
            <option>Docker</option>
            <option>Kubernetes</option>
            <option>DevOps</option>
            <option>Cybersecurity</option>
            <option>Blockchain</option>
            <option>Flutter</option>
            <option>Android Development</option>
            <option>Digital Marketing</option>
            <option>Financial Analysis</option>
            <option>Medical Coding</option>

          </select>

          {/* Location */}
          <select name="Location" value={form.Location} onChange={handleChange} required>

            <option value="">Select Location</option>

            <option>Bangalore</option>
            <option>Hyderabad</option>
            <option>Chennai</option>
            <option>Pune</option>
            <option>Mumbai</option>
            <option>Delhi NCR</option>
            <option>Noida</option>
            <option>Gurugram</option>
            <option>Kolkata</option>
            <option>Coimbatore</option>

          </select>

          <button type="submit" className="predict-btn">
            Predict Salary
          </button>

        </form>

        {salary && (
          <div className="result-box">
            <h3>Predicted Salary</h3>
            <p>₹ {salary}</p>
          </div>
        )}

      </div>
    </div>
  );
};

export default NewPrediction;
